function initLanguageSliders() {
    document.querySelectorAll('.lang-slider').forEach(slider => {
        const options = slider.querySelectorAll('.lang-option');
        const indicator = slider.querySelector('.lang-slider-indicator');

        options.forEach(option => {
            option.addEventListener('click', (e) => {
                e.preventDefault();
                options.forEach(opt => opt.classList.remove('active'));
                option.classList.add('active');
                if (indicator && !slider.classList.contains('mobile-lang')) {
                    indicator.style.transform = `translateX(${option.offsetLeft - 2}px)`;
                    if (option.offsetWidth > 36) {
                        indicator.style.width = `${option.offsetWidth - 4}px`;
                    }
                }
                if (slider.classList.contains('mobile-lang')) {
                    options.forEach(opt => {
                        opt.style.background = opt.classList.contains('active') ? 'var(--gold)' : 'var(--blush)';
                        opt.style.color = opt.classList.contains('active') ? 'var(--white)' : 'var(--charcoal)';
                    });
                }
            });
        });
    });
}

function syncSliderToLang(lang) {
    document.querySelectorAll('.lang-option').forEach(opt => {
        if (opt.dataset.lang === lang) {
            opt.classList.add('active');
            const slider = opt.closest('.lang-slider');
            if (slider) {
                const indicator = slider.querySelector('.lang-slider-indicator');
                if (indicator && !slider.classList.contains('mobile-lang')) {
                    indicator.style.transform = `translateX(${opt.offsetLeft - 2}px)`;
                }
            }
        } else {
            opt.classList.remove('active');
        }
    });
}

document.addEventListener("DOMContentLoaded", () => {
    initLanguageSliders();
    // Load saved language from localStorage or default to English
    const savedLang = localStorage.getItem("language") || "en";
    changeLanguage(savedLang);
    syncSliderToLang(savedLang);
});

function changeLanguage(lang) {
    document.documentElement.setAttribute("lang", lang);
    localStorage.setItem("language", lang); // Save language preference

    if (lang === "ar") {
        document.body.setAttribute("dir", "rtl");
        document.body.style.textAlign = "right";
    } else {
        document.body.setAttribute("dir", "ltr");
        document.body.style.textAlign = "left";
    }

    document.querySelectorAll("[data-key]").forEach(element => {
        translateElement(element, lang);
    });

    syncSliderToLang(lang);
}

function translateElement(element, lang) {
    const key = element.getAttribute("data-key");

    if (!element.querySelector("a") && translations[lang][key]) {
        element.innerHTML = translations[lang][key];
        return;
    }

    if (translations[lang][key]) {
        const originalLinks = Array.from(element.querySelectorAll("a"));
        const linkKeys = [
            "link-denis-acker", "link-acker-choquette", "link-canadian-attorney",
            "link-legal-firm", "link-quebec-bar", "link-company-formation",
            "link-trusts-foundations", "link-investment-immigration", "link-malta",
            "link-eu-countries"
        ];

        const textParts = translations[lang][key].split(/<br\s*\/?>/i);
        element.innerHTML = "";
        let currentLinkIndex = 0;

        textParts.forEach((part, index) => {
            const tempDiv = document.createElement("div");
            tempDiv.innerHTML = part;
            const textNodes = Array.from(tempDiv.childNodes);

            textNodes.forEach(node => {
                if (node.nodeType === Node.TEXT_NODE) {
                    element.appendChild(document.createTextNode(node.textContent));
                }
            });

            if (currentLinkIndex < originalLinks.length) {
                const originalLink = originalLinks[currentLinkIndex];
                const newLink = document.createElement("a");
                newLink.href = originalLink.href;
                newLink.target = originalLink.target || "";
                newLink.textContent = translations[lang][linkKeys[currentLinkIndex]];
                element.appendChild(newLink);
                currentLinkIndex++;
            }

            if (index < textParts.length - 1) {
                element.appendChild(document.createElement("br"));
            }
        });
    }
}